import{_ as i,p as l,q as e,a1 as a}from"./framework-822ca1a4.js";const n={},r=a('<h1 id="现在进行时" tabindex="-1"><a class="header-anchor" href="#现在进行时" aria-hidden="true">#</a> 现在进行时</h1><p>现在进行时态主要表示“此时此刻正在做某事”，现在进行时态大部分都是动作的句子。</p><h2 id="构成方式" tabindex="-1"><a class="header-anchor" href="#构成方式" aria-hidden="true">#</a> 构成方式</h2><p>主语 + be + 动词的现在分词 + 宾语</p><p>注意：现在进行时态也需要 be 动词，但是这里的 be 动词是没有意思的，它是为了和动词的现在分词构成一个复合谓语，帮助构成现在进行时态。而系动词 be 的意思是“是...”。</p><p>现在进行时态一般不需要时间状语。因为它本来就是表示此时此刻的。也可以加时间状语，例如：now，right now， at the moment。</p><p>现在进行时态对做谓语的动词要求比较多，不是每个动词都能用于现在进行时态。一般不能用做现在进行时态的动词有：表示知觉/结果/态度/情感的动词。这个在权威词典（例如牛津词典）中都有规定，用的时候可以先查一下能不能用于现在进行时态。</p><h2 id="基本句型" tabindex="-1"><a class="header-anchor" href="#基本句型" aria-hidden="true">#</a> 基本句型</h2><ol><li>人称代词主格 + is/are/am + 不及物动词的现在分词</li></ol><ul><li>I am working.</li><li>You are running.</li><li>She is dancing.</li><li>He is laughing.</li><li>It is running.</li><li>We are walking.</li><li>They are singing.</li></ul><ol start="2"><li>名词 + is/are + 不及物动词的现在分词</li></ol><ul><li>My leader is working.</li><li>My fans are dancing</li></ul><ol start="3"><li>人称代词主格 + is/are/am + 及物动词的现在分词 + 宾语</li></ol><ul><li>I am cleaning my office.</li><li>She is baking beef.</li><li>They are helping an old man.</li></ul><ol start="4"><li>名词 + is/are + 及物动词的现在分词 + 宾语</li></ol><ul><li>Her leader is cleaning his office.</li><li>These bodyguards are pushing a car.</li></ul><p>变否定句，在 be 动词后面加 not 即可。</p><ul><li>I am not cleaning my office.</li><li>She is not baking beef.</li><li>These bodyguards aren&#39;t pushing a car.</li></ul><p>变疑问句，把助动词移到句首，其他不变。</p><ul><li>Are you cleaning your office?</li><li>Is she baking beef?</li></ul><h2 id="现在进行时态的特殊用法" tabindex="-1"><a class="header-anchor" href="#现在进行时态的特殊用法" aria-hidden="true">#</a> 现在进行时态的特殊用法</h2><ol><li>表示目前一段时间内正在进行的动作。</li></ol><p>I am writing a new book this week</p><ol start="2"><li>与副词 always，constantly 等连用，表示反复出现或习惯性动作，类似于一般现在时态的作用，但强调感情色彩。</li></ol><ul><li>Your mother is always giving you money. 你妈妈总是给你钱（表示羡慕）</li><li>Your mother always gives you money.</li></ul><ol start="3"><li>表示按计划安排即将发生的动作，强调“一定发生，马上发生”，而且是谓语必须是那种不能表示“此时此刻动作的动词”。</li></ol><p>She is dying. （表示她马上要死了，而不是它正在死）</p><ol start="4"><li>一般情况下，现在进行时态只有表示动作的句子，但是特殊情况下，主系表也可以有现在进行时态。</li></ol><ul><li>I am just being funny.</li><li>We are getting older.</li></ul>',29),o=[r];function s(t,h){return l(),e("div",null,o)}const d=i(n,[["render",s],["__file","present-tense-2.html.vue"]]);export{d as default};
